-- ============================================================================
-- 5. accounting_journal_entries – Journal entry headers
--    From migration 008
-- ============================================================================
CREATE TABLE IF NOT EXISTS accounting_journal_entries (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  entry_number  VARCHAR(30)  NOT NULL UNIQUE,
  entry_type    VARCHAR(30)  NOT NULL CHECK (entry_type IN ('payment','refund','invoice_issued','invoice_payment','reconciliation','fee','adjustment')),
  description   TEXT         NOT NULL,
  booking_id    INTEGER      REFERENCES bookings(id) ON DELETE SET NULL,
  invoice_id    UUID         REFERENCES invoices(id) ON DELETE SET NULL,
  payment_id    INTEGER      REFERENCES payments(id) ON DELETE SET NULL,
  entry_date    DATE         NOT NULL,
  posting_date  DATE,
  created_by    INTEGER      NOT NULL REFERENCES users(id),
  approved_by   INTEGER      REFERENCES users(id),
  created_at    TIMESTAMPTZ  NOT NULL DEFAULT NOW(),
  updated_at    TIMESTAMPTZ  NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_journal_entries_entry_date ON accounting_journal_entries(entry_date);
CREATE INDEX IF NOT EXISTS idx_journal_entries_booking_id ON accounting_journal_entries(booking_id);
CREATE INDEX IF NOT EXISTS idx_journal_entries_invoice_id ON accounting_journal_entries(invoice_id);
CREATE INDEX IF NOT EXISTS idx_journal_entries_entry_type ON accounting_journal_entries(entry_type);

-- ============================================================================
-- 6. accounting_journal_lines – Journal entry detail lines
--    From migration 008
-- ============================================================================
CREATE TABLE IF NOT EXISTS accounting_journal_lines (
  id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  entry_id          UUID           NOT NULL REFERENCES accounting_journal_entries(id) ON DELETE CASCADE,
  account_id        UUID           NOT NULL REFERENCES chart_of_accounts(id),
  debit_amount_gbp  DECIMAL(10,2)  NOT NULL DEFAULT 0,
  credit_amount_gbp DECIMAL(10,2)  NOT NULL DEFAULT 0,
  description       TEXT,
  created_at        TIMESTAMPTZ    NOT NULL DEFAULT NOW(),

  -- Amounts must be non-negative
  CONSTRAINT chk_journal_line_amounts_non_negative
    CHECK (debit_amount_gbp >= 0 AND credit_amount_gbp >= 0),

  -- Each line must have at least one side (debit or credit)
  CONSTRAINT chk_journal_line_at_least_one_side
    CHECK (NOT (debit_amount_gbp = 0 AND credit_amount_gbp = 0)),

  -- A line cannot be both debit AND credit
  CONSTRAINT chk_journal_line_not_both_sides
    CHECK (NOT (debit_amount_gbp > 0 AND credit_amount_gbp > 0))
);

CREATE INDEX IF NOT EXISTS idx_journal_lines_entry_id ON accounting_journal_lines(entry_id);
CREATE INDEX IF NOT EXISTS idx_journal_lines_account_id ON accounting_journal_lines(account_id);

-- ============================================================================
-- 7. payment_reminders – Payment reminder scheduling
--    From migration 009
-- ============================================================================
CREATE TABLE IF NOT EXISTS payment_reminders (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  booking_id      INTEGER      REFERENCES bookings(id) ON DELETE CASCADE,
  invoice_id      UUID         REFERENCES invoices(id) ON DELETE CASCADE,
  reminder_type   VARCHAR(20)  NOT NULL
                  CHECK (reminder_type IN ('payment_due','overdue_1d','overdue_7d','overdue_30d')),
  scheduled_at    TIMESTAMPTZ  NOT NULL,
  sent_at         TIMESTAMPTZ,
  sent_to         VARCHAR(255),
  status          VARCHAR(20)  NOT NULL DEFAULT 'pending'
                  CHECK (status IN ('pending','sent','failed','cancelled')),
  error_message   TEXT,
  created_at      TIMESTAMPTZ  NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_reminders_status ON payment_reminders(status);
CREATE INDEX IF NOT EXISTS idx_reminders_scheduled_at ON payment_reminders(scheduled_at);
CREATE INDEX IF NOT EXISTS idx_reminders_booking_id ON payment_reminders(booking_id);
CREATE INDEX IF NOT EXISTS idx_reminders_invoice_id ON payment_reminders(invoice_id);

-- ============================================================================
-- 8. stripe_payments – Stripe Checkout Session tracking
--    From migration 010
-- ============================================================================
CREATE TABLE IF NOT EXISTS stripe_payments (
  id                        UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  payment_id                INTEGER        NOT NULL REFERENCES payments(id) ON DELETE CASCADE,
  stripe_session_id         VARCHAR(255)   NOT NULL UNIQUE,
  stripe_payment_intent_id  VARCHAR(255),
  stripe_customer_id        VARCHAR(255),
  amount_gbp                DECIMAL(10,2)  NOT NULL,
  currency                  VARCHAR(3)     NOT NULL DEFAULT 'GBP',
  status                    VARCHAR(30)    NOT NULL DEFAULT 'pending'
                            CHECK (status IN (
                              'pending',
                              'requires_payment_method',
                              'requires_confirmation',
                              'requires_action',
                              'processing',
                              'succeeded',
                              'failed',
                              'refunded',
                              'partially_refunded'
                            )),
  payment_method_details    JSONB,
  receipt_url               TEXT,
  refund_amount_gbp         DECIMAL(10,2)  NOT NULL DEFAULT 0,
  refunded_at               TIMESTAMPTZ,
  error_message             TEXT,
  idempotency_key           VARCHAR(255),
  created_at                TIMESTAMPTZ    NOT NULL DEFAULT NOW(),
  updated_at                TIMESTAMPTZ    NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_stripe_payments_session_id ON stripe_payments(stripe_session_id);
CREATE INDEX IF NOT EXISTS idx_stripe_payments_payment_intent_id ON stripe_payments(stripe_payment_intent_id);
CREATE INDEX IF NOT EXISTS idx_stripe_payments_payment_id ON stripe_payments(payment_id);
CREATE INDEX IF NOT EXISTS idx_stripe_payments_idempotency_key ON stripe_payments(idempotency_key);

-- ============================================================================
-- 9. bank_transactions – Bank reconciliation
--    From migration 011
-- ============================================================================
CREATE TABLE IF NOT EXISTS bank_transactions (
  id                      UUID            PRIMARY KEY DEFAULT gen_random_uuid(),
  external_id             VARCHAR(255),
  transaction_date        DATE            NOT NULL,
  description             TEXT            NOT NULL,
  amount_gbp              DECIMAL(10,2)   NOT NULL,
  balance_gbp             DECIMAL(10,2),
  reference               VARCHAR(255),
  payment_id              INTEGER         REFERENCES payments(id) ON DELETE SET NULL,
  reconciliation_status   VARCHAR(20)     NOT NULL DEFAULT 'unmatched'
                          CHECK (reconciliation_status IN (
                            'unmatched',
                            'matched',
                            'disputed'
                          )),
  matched_at              TIMESTAMPTZ,
  matched_by              INTEGER         REFERENCES users(id),
  import_batch_id         VARCHAR(50),
  raw_data                JSONB,
  notes                   TEXT,
  created_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW(),
  updated_at              TIMESTAMPTZ     NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_bank_transactions_date ON bank_transactions(transaction_date);
CREATE INDEX IF NOT EXISTS idx_bank_transactions_status ON bank_transactions(reconciliation_status);
CREATE INDEX IF NOT EXISTS idx_bank_transactions_payment_id ON bank_transactions(payment_id);
CREATE INDEX IF NOT EXISTS idx_bank_transactions_import_batch ON bank_transactions(import_batch_id);
CREATE INDEX IF NOT EXISTS idx_bank_transactions_external_id ON bank_transactions(external_id);

-- ============================================================================
-- 10. export_log – Export tracking for external accounting systems
--     From migration 012
-- ============================================================================
CREATE TABLE IF NOT EXISTS export_log (
  id                UUID            PRIMARY KEY DEFAULT gen_random_uuid(),
  export_type       VARCHAR(30)     NOT NULL
                    CHECK (export_type IN ('csv','xml','xero','quickbooks','sage','other')),
  export_format     VARCHAR(10)     NOT NULL
                    CHECK (export_format IN ('csv','xml','json')),
  date_from         DATE            NOT NULL,
  date_to           DATE            NOT NULL,
  record_count      INTEGER         NOT NULL DEFAULT 0,
  total_amount_gbp  DECIMAL(10,2)   NOT NULL DEFAULT 0,
  status            VARCHAR(20)     NOT NULL DEFAULT 'completed'
                    CHECK (status IN ('completed','failed','partial')),
  file_path         TEXT,
  error_message     TEXT,
  exported_by       INTEGER         NOT NULL REFERENCES users(id),
  created_at        TIMESTAMPTZ     NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_export_log_type ON export_log(export_type);
CREATE INDEX IF NOT EXISTS idx_export_log_date_range ON export_log(date_from, date_to);
CREATE INDEX IF NOT EXISTS idx_export_log_exported_by ON export_log(exported_by);


-- ============================================================================
-- End of file section
-- ============================================================================

-- ============================================================================
-- FIGAS Airline Booking System – Scheduling & Operations Tables
-- Consolidated from migrations: 014, 019 (scheduling parts)
--
-- This file contains scheduling-related tables: schedules, flight_legs,
-- pilot_assignments, weight_balance_snapshots, and ALTER TABLE additions
-- to flights and aerodromes.
-- ============================================================================

BEGIN;

-- ============================================================================
-- 1. schedules – Daily flight schedules
--    From migration 014, with audit columns from migration 019
-- ============================================================================
CREATE TABLE IF NOT EXISTS schedules (
  id SERIAL PRIMARY KEY,
  schedule_date DATE NOT NULL,
  status VARCHAR(20) NOT NULL DEFAULT 'draft' CHECK (status IN ('building', 'draft', 'approved', 'published', 'cancelled', 'pilot_assigned', 'loadsheet_generated', 'in_progress', 'completed')),
  created_by INTEGER NOT NULL REFERENCES users(id),
  updated_by INTEGER REFERENCES users(id),
  approved_by INTEGER REFERENCES users(id),
  approved_at TIMESTAMP WITH TIME ZONE,
  published_by INTEGER REFERENCES users(id),
  published_at TIMESTAMP WITH TIME ZONE,
  notes TEXT,
  cancelled_by INTEGER REFERENCES users(id),
  cancelled_at TIMESTAMP WITH TIME ZONE,
  cancellation_reason TEXT,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  UNIQUE(schedule_date)
);

CREATE INDEX IF NOT EXISTS idx_schedules_date ON schedules(schedule_date);
CREATE INDEX IF NOT EXISTS idx_schedules_status ON schedules(status);

-- ============================================================================
-- 2. flight_legs – Individual legs of a multi-stop flight
--    From migration 014
-- ============================================================================
CREATE TABLE IF NOT EXISTS flight_legs (
  id SERIAL PRIMARY KEY,
  flight_id INTEGER NOT NULL REFERENCES flights(id) ON DELETE CASCADE,
  leg_number INTEGER NOT NULL,
  origin_code VARCHAR(10) NOT NULL,
  destination_code VARCHAR(10) NOT NULL,
  distance_nm DECIMAL(10,2),
  heading DECIMAL(10,2),
  etd TIMESTAMP WITH TIME ZONE,
  eta TIMESTAMP WITH TIME ZONE,
  atd TIMESTAMP WITH TIME ZONE,
  ata TIMESTAMP WITH TIME ZONE,
  pax_on INTEGER DEFAULT 0,
  pax_off INTEGER DEFAULT 0,
  bags_on INTEGER DEFAULT 0,
  bags_off INTEGER DEFAULT 0,
  fuel_uplift_kg DECIMAL(10,2) DEFAULT 0,
  fuel_on_board_kg DECIMAL(10,2) DEFAULT 0,
  tow_kg DECIMAL(10,2) DEFAULT 0,
  lw_kg DECIMAL(10,2) DEFAULT 0,
  status VARCHAR(20) NOT NULL DEFAULT 'scheduled' CHECK (status IN ('scheduled', 'active', 'completed', 'cancelled')),
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  UNIQUE(flight_id, leg_number)
);

CREATE INDEX IF NOT EXISTS idx_flight_legs_flight_id ON flight_legs(flight_id);

-- ============================================================================
-- 3. pilot_assignments – Pilot-to-flight assignments
--    From migration 014, with schedule_id FK and audit columns from 019
-- ============================================================================
CREATE TABLE IF NOT EXISTS pilot_assignments (
  id SERIAL PRIMARY KEY,
  flight_id INTEGER NOT NULL REFERENCES flights(id) ON DELETE CASCADE,
  pilot_id INTEGER NOT NULL REFERENCES pilots(id),
  role VARCHAR(20) NOT NULL CHECK (role IN ('captain', 'first_officer', 'relief')),
  status VARCHAR(20) NOT NULL DEFAULT 'assigned' CHECK (status IN ('assigned', 'confirmed', 'declined', 'checked_in', 'completed', 'cancelled')),
  schedule_id INTEGER REFERENCES schedules(id) ON DELETE CASCADE,
  confirmed_at TIMESTAMP WITH TIME ZONE,
  declined_at TIMESTAMP WITH TIME ZONE,
  declined_reason TEXT,
  notes TEXT,
  assigned_by INTEGER REFERENCES users(id),
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  UNIQUE(flight_id, pilot_id)
);

CREATE INDEX IF NOT EXISTS idx_pilot_assignments_flight_id ON pilot_assignments(flight_id);
CREATE INDEX IF NOT EXISTS idx_pilot_assignments_pilot_id ON pilot_assignments(pilot_id);
CREATE INDEX IF NOT EXISTS idx_pilot_assignments_schedule_id ON pilot_assignments(schedule_id);

-- ============================================================================
-- 4. weight_balance_snapshots – Weight & balance calculations per flight leg
--    From migration 019 (complete version with all columns).
--    NOTE: The earlier version from migration 014 is superseded by this.
-- ============================================================================
CREATE TABLE IF NOT EXISTS weight_balance_snapshots (
  id SERIAL PRIMARY KEY,
  flight_leg_id INTEGER NOT NULL REFERENCES flight_legs(id) ON DELETE CASCADE,
  schedule_id INTEGER REFERENCES schedules(id) ON DELETE CASCADE,
  passenger_weight_kg DECIMAL(10,2) NOT NULL DEFAULT 0,
  baggage_weight_kg DECIMAL(10,2) NOT NULL DEFAULT 0,
  freight_weight_kg DECIMAL(10,2) NOT NULL DEFAULT 0,
  fuel_weight_kg DECIMAL(10,2) NOT NULL DEFAULT 0,
  crew_weight_kg DECIMAL(10,2) NOT NULL DEFAULT 0,
  empty_weight_kg DECIMAL(10,2) NOT NULL DEFAULT 0,
  total_weight_kg DECIMAL(10,2) NOT NULL DEFAULT 0,
  required_fuel_kg DECIMAL(10,2),
  minimum_fuel_kg DECIMAL(10,2),
  fuel_state VARCHAR(20),
  fuel_rule_applied TEXT,
  total_moment_kgm DECIMAL(10,2),
  cg_position_pct DECIMAL(10,2),
  effective_mtow_kg DECIMAL(10,2),
  effective_mlw_kg DECIMAL(10,2),
  mtow_used_pct DECIMAL(10,2),
  mlw_used_pct DECIMAL(10,2),
  binding_constraint VARCHAR(20),
  binding_constraint_detail TEXT,
  computed_by VARCHAR(50) NOT NULL DEFAULT 'system',
  computed_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  notes TEXT,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_wbs_flight_leg_id ON weight_balance_snapshots(flight_leg_id);
CREATE INDEX IF NOT EXISTS idx_wbs_schedule_id ON weight_balance_snapshots(schedule_id);

COMMIT;


-- ============================================================================
-- End of file section
-- ============================================================================

-- ============================================================================
-- FIGAS Airline Booking System – PBAC (Permission-Based Access Control)
-- Consolidated from migration: 015
--
-- This file contains all RBAC/PBAC tables: roles, permissions,
-- role_permissions, user_roles, and audit_log, plus seed data.
-- ============================================================================

BEGIN;

-- ============================================================================
-- 1. roles – Role definitions
-- ============================================================================
CREATE TABLE IF NOT EXISTS roles (
    id SERIAL PRIMARY KEY,
    slug VARCHAR(50) NOT NULL UNIQUE,
    name VARCHAR(50) NOT NULL,
    description TEXT,
    hierarchy_level INTEGER NOT NULL DEFAULT 0,
    is_system BOOLEAN NOT NULL DEFAULT false,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_roles_hierarchy ON roles(hierarchy_level);

-- ============================================================================
-- 2. permissions – Permission definitions
-- ============================================================================
CREATE TABLE IF NOT EXISTS permissions (
    id SERIAL PRIMARY KEY,
    resource VARCHAR(50) NOT NULL,
    action VARCHAR(50) NOT NULL,
    description TEXT,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    UNIQUE(resource, action)
);

-- ============================================================================
-- 3. role_permissions – Role-permission junction table
-- ============================================================================
CREATE TABLE IF NOT EXISTS role_permissions (
    id SERIAL PRIMARY KEY,
    role_id INTEGER NOT NULL REFERENCES roles(id) ON DELETE CASCADE,
    permission_id INTEGER NOT NULL REFERENCES permissions(id) ON DELETE CASCADE,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    UNIQUE(role_id, permission_id)
);

CREATE INDEX IF NOT EXISTS idx_role_permissions_role_id ON role_permissions(role_id);
CREATE INDEX IF NOT EXISTS idx_role_permissions_permission_id ON role_permissions(permission_id);

-- ============================================================================
-- 4. user_roles – User-role junction table
-- ============================================================================
CREATE TABLE IF NOT EXISTS user_roles (
    id SERIAL PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    role_id INTEGER NOT NULL REFERENCES roles(id) ON DELETE CASCADE,
    assigned_by INTEGER REFERENCES users(id) ON DELETE SET NULL,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    UNIQUE(user_id, role_id)
);

CREATE INDEX IF NOT EXISTS idx_user_roles_user_id ON user_roles(user_id);
CREATE INDEX IF NOT EXISTS idx_user_roles_role_id ON user_roles(role_id);

-- ============================================================================
-- 5. audit_log – Audit trail
-- ============================================================================
CREATE TABLE IF NOT EXISTS audit_log (
    id SERIAL PRIMARY KEY,
    actor_id INTEGER NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
    action VARCHAR(100) NOT NULL,
    entity_type VARCHAR(50),
    entity_id INTEGER,
    old_values JSONB,
    new_values JSONB,
    ip_address VARCHAR(45),
    user_agent VARCHAR(255),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_audit_log_actor_id ON audit_log(actor_id);
CREATE INDEX IF NOT EXISTS idx_audit_log_action ON audit_log(action);
CREATE INDEX IF NOT EXISTS idx_audit_log_entity ON audit_log(entity_type, entity_id);
CREATE INDEX IF NOT EXISTS idx_audit_log_created_at ON audit_log(created_at);

