-- End of file section
-- ============================================================================

-- 011-flight-logs.sql
-- Records actual flown data (block times, tach, fuel, cycles) per flight.
-- Separate from the operational flights table used for scheduling.

CREATE TABLE IF NOT EXISTS flight_logs (
    id              SERIAL PRIMARY KEY,
    flight_id       INTEGER REFERENCES flights(id) ON DELETE SET NULL,
    aircraft_id     INTEGER NOT NULL REFERENCES aircraft(id),
    captain_id      INTEGER REFERENCES pilots(id),
    departure_date  DATE NOT NULL DEFAULT CURRENT_DATE,
    block_off_time  TIME,
    block_on_time   TIME,
    tach_start      NUMERIC(7,1),
    tach_end        NUMERIC(7,1),
    cycles          INTEGER NOT NULL DEFAULT 1,
    fuel_uplift_ltr INTEGER,
    fuel_start_ltr  INTEGER,
    fuel_end_ltr    INTEGER,
    oil_uplift_ltr  NUMERIC(3,1),
    origin_code     VARCHAR(10),
    destination_code VARCHAR(10),
    remarks         TEXT,
    created_by      INTEGER,
    created_at      TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_flight_logs_aircraft ON flight_logs(aircraft_id, departure_date);
CREATE INDEX IF NOT EXISTS idx_flight_logs_date ON flight_logs(departure_date);


-- ============================================================================
-- End of file section
-- ============================================================================

-- 012-maintenance-tasks.sql
-- Scheduled inspections, work orders, and maintenance activities.

CREATE TABLE IF NOT EXISTS maintenance_tasks (
    id              SERIAL PRIMARY KEY,
    aircraft_id     INTEGER NOT NULL REFERENCES aircraft(id),
    task_type       VARCHAR(50) NOT NULL DEFAULT 'inspection',
    ata_chapter     VARCHAR(10),
    title           VARCHAR(255) NOT NULL,
    description     TEXT,
    interval_type   VARCHAR(20) NOT NULL DEFAULT 'hours',
    interval_value  INTEGER NOT NULL,
    last_completed_at TIMESTAMPTZ,
    last_completed_hours NUMERIC(7,1),
    last_completed_cycles INTEGER DEFAULT 0,
    next_due_hours  NUMERIC(7,1),
    next_due_date   DATE,
    status          VARCHAR(20) DEFAULT 'open',
    assigned_to     INTEGER REFERENCES users(id),
    priority        VARCHAR(10) DEFAULT 'routine',
    created_at      TIMESTAMPTZ DEFAULT NOW(),
    completed_at    TIMESTAMPTZ,
    completed_by    INTEGER REFERENCES users(id)
);

CREATE INDEX IF NOT EXISTS idx_maint_tasks_aircraft ON maintenance_tasks(aircraft_id, status);
CREATE INDEX IF NOT EXISTS idx_maint_tasks_status ON maintenance_tasks(status);


-- ============================================================================
-- End of file section
-- ============================================================================

-- 013-defects.sql
-- Defect/Snag tracker with MEL references and deferral workflow.

CREATE TABLE IF NOT EXISTS defects (
    id              SERIAL PRIMARY KEY,
    aircraft_id     INTEGER NOT NULL REFERENCES aircraft(id),
    flight_log_id   INTEGER REFERENCES flight_logs(id),
    reported_by     INTEGER NOT NULL REFERENCES users(id),
    reported_at     TIMESTAMPTZ DEFAULT NOW(),
    ata_chapter     VARCHAR(10),
    title           VARCHAR(255) NOT NULL,
    description     TEXT,
    severity        VARCHAR(20) DEFAULT 'minor',
    mel_reference   VARCHAR(50),
    mel_category    VARCHAR(1),
    deferral_status VARCHAR(20) DEFAULT 'open',
    deferral_approved_by INTEGER REFERENCES users(id),
    deferral_expiry_date DATE,
    rectification   TEXT,
    rectified_at    TIMESTAMPTZ,
    rectified_by    INTEGER REFERENCES users(id),
    maintenance_task_id INTEGER REFERENCES maintenance_tasks(id),
    created_at      TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_defects_aircraft ON defects(aircraft_id, deferral_status);
CREATE INDEX IF NOT EXISTS idx_defects_open ON defects(deferral_status) WHERE deferral_status != 'closed';


-- ============================================================================
-- End of file section
-- ============================================================================

-- 014-lifed-components.sql
-- Life-limited parts (LLPs) with TBO/TSO tracking.

CREATE TABLE IF NOT EXISTS lifed_components (
    id              SERIAL PRIMARY KEY,
    aircraft_id     INTEGER NOT NULL REFERENCES aircraft(id),
    component_name  VARCHAR(255) NOT NULL,
    part_number     VARCHAR(100),
    serial_number   VARCHAR(100),
    ata_chapter     VARCHAR(10),
    tbo_hours       NUMERIC(7,1) NOT NULL,
    tbo_cycles      INTEGER,
    tbo_calendar_months INTEGER,
    installed_hours NUMERIC(7,1) NOT NULL,
